"import { useEffect } from 'react';
import { ref, set, get, update, onValue, runTransaction } from 'firebase/database';
import { db } from '../config/firebase';

// Hook to subscribe to a room's state
export function useFirebaseRoom(roomCode, callback) {
    useEffect(() => {
        if (!roomCode) return;
        const roomRef = ref(db, `rooms/${roomCode}`);

        const unsubscribe = onValue(roomRef, (snapshot) => {
            if (snapshot.exists()) {
                callback(snapshot.val());
            }
        });

        return () => unsubscribe();
    }, [roomCode, callback]);
}

// Function to create a room
export async function createRoom(roomCode, hostPlayer, category) {
    const roomRef = ref(db, `rooms/${roomCode}`);
    const initialRoom = {
        category,
        phase: 'lobby',
        hostId: hostPlayer.uid,
        players: {
            [hostPlayer.uid]: {
                name: hostPlayer.name,
                isHost: true,
                score: 0
            }
        }
    };
    await set(roomRef, initialRoom);
}

// Function to join a room
export async function joinRoom(roomCode, player) {
    const playerRef = ref(db, `rooms/${roomCode}/players/${player.uid}`);
    await set(playerRef, {
        name: player.name,
        isHost: false,
        score: 0
    });
}

// Function to start a game (assign roles and change phase)
export async function startGame(roomCode, roles, word) {
    const roomRef = ref(db, `rooms/${roomCode}`);
    await update(roomRef, {
        roles,
        word,
        phase: 'roleReveal'
    });
}

