"import { useEffect, useRef } from 'react';
import { ref, set, get, update, onValue, runTransaction } from 'firebase/database';
import { db } from '../config/firebase';

// Hook to subscribe to a room's state
export function useFirebaseRoom(roomCode, callback) {
    const callbackRef = useRef(callback);

    // Keep callbackRef updated on every render
    useEffect(() => {
        callbackRef.current = callback;
    });

    useEffect(() => {
        if (!roomCode) return;
        const roomRef = ref(db, `rooms/${roomCode}`);

        const unsubscribe = onValue(roomRef, (snapshot) => {
            if (snapshot.exists() && callbackRef.current) {
                callbackRef.current(snapshot.val());
            }
        });

        return () => unsubscribe();
    }, [roomCode]);
}"

